-- Seed of programming-basics tasks so a freshly generated map has enough tasks.
-- All open-question (manual review). Mix of difficulties: easy/medium/hard/core.

WITH d_easy AS (SELECT id FROM difficulty_levels WHERE slug='easy'),
     d_medium AS (SELECT id FROM difficulty_levels WHERE slug='medium'),
     d_hard AS (SELECT id FROM difficulty_levels WHERE slug='hard'),
     d_core AS (SELECT id FROM difficulty_levels WHERE slug='core')

